const RUBROS = {
  informatica: ['informatic','tecnolog','software','hardware','sistema','licencia','computadora','servidor','internet','digital','electroni','impres','monitor','teclado','mouse','router','switch','firewall','ups'],
  ferreteria: ['ferreter','herramienta','tornillo','pintura','construcc','materiales','buloneria','soldadura','tubo','cable elect'],
  indumentaria: ['indumentaria','calzado','ropa','uniforme','vestimenta','textil','tela','prenda','campera','pantalon','camisa','bota'],
  epp: ['epp','protecci personal','casco','guante','chaleco','barbijo','seguridad laboral','equipo de protecci','antiparras','respirador','mameluco','arnes'],
  bazar: ['bazar','vajilla','utensilio','cocina','menaje','cristaler','cubierto','olla','bandeja','cafetera','dispenser'],
  mantenimiento: ['mantenimiento','limpieza','edificio','plomeria','electricidad','electric','sanitario','aire acondicionado','ascensor','jardineria','fumigacion','conservacion','reparacion'],
};
const norm = s => { if (s == null) return ''; return String(s).toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,''); };
const prev = $('Extraer ViewState').first().json;
const hoyISO = prev.fechaHoyISO;
const hoyDisplay = prev.fechaHoyDisplay;
let alta=0, media=0, baja=0;
const licitaciones = [];
for (const item of $input.all()) {
  const row = item.json;
  if (!row || Object.keys(row).length === 0) continue;
  const tituloKey = Object.keys(row).find(k => norm(k).includes('denominac') || norm(k).includes('nombre') || norm(k).includes('descripc'));
  const titulo = tituloKey ? String(row[tituloKey]) : '';
  if (!norm(titulo)) continue;
  const numeroKey = Object.keys(row).find(k => norm(k).includes('numero') || norm(k).includes('nro') || norm(k).includes('proceso') || norm(k).includes('expediente'));
  const numero = numeroKey ? String(row[numeroKey]) : '';
  const orgKey = Object.keys(row).find(k => norm(k).includes('reparticion') || norm(k).includes('organismo') || norm(k).includes('jurisdiccion') || norm(k).includes('unidad'));
  const organismo = orgKey ? String(row[orgKey]) : '';
  const fechaKey = Object.keys(row).find(k => norm(k).includes('apertura') || norm(k).includes('cierre'));
  const fechaCierreRaw = fechaKey ? String(row[fechaKey]) : '';
  const montoKey = Object.keys(row).find(k => norm(k).includes('monto') || norm(k).includes('presupuesto') || norm(k).includes('importe'));
  const montoRaw = montoKey ? row[montoKey] : null;
  const monto = montoRaw ? parseFloat(String(montoRaw).replace(/[$.,\s]/g,'')) : null;
  let rubroMatch = null;
  const tituloNorm = norm(titulo);
  for (const [rubro, kws] of Object.entries(RUBROS)) {
    if (kws.some(kw => tituloNorm.includes(norm(kw)))) { rubroMatch = rubro; break; }
  }
  if (!rubroMatch) continue;
  let fechaCierreISO = null, diasAlCierre = null;
  const m = fechaCierreRaw.match(/(\d{1,2})[\/\-](\d{1,2})[\/\-](\d{4})/);
  if (m) { const [,d,mo,y] = m; fechaCierreISO=`${y}-${mo.padStart(2,'0')}-${d.padStart(2,'0')}`; diasAlCierre=Math.ceil((new Date(fechaCierreISO+'T23:59:59')-new Date(hoyISO+'T00:00:00'))/86400000); }
  let score = 50;
  if (monto!=null&&!isNaN(monto)) { if(monto>=5000000)score+=15; else if(monto>=1000000)score+=10; else if(monto>=500000)score+=5; else score+=2; } else score+=5;
  if (diasAlCierre!=null) { if(diasAlCierre<=0)score+=0; else if(diasAlCierre<=3)score+=5; else if(diasAlCierre<=7)score+=10; else if(diasAlCierre<=15)score+=15; else score+=8; }
  const prioridad = score>=70?'alta':score>=40?'media':'baja';
  if(prioridad==='alta')alta++; else if(prioridad==='media')media++; else baja++;
  licitaciones.push({portal:'caba',numero:numero.trim(),titulo:titulo.trim(),organismo:organismo.trim(),rubro:rubroMatch,monto_estimado:(monto!=null&&!isNaN(monto))?monto:null,fecha_publicacion:null,fecha_cierre:fechaCierreISO,url:'https://www.buenosairescompras.gob.ar/BuscarAvanzado.aspx',estado:'nueva',score,prioridad,participacion_previa:false});
}
return [{json:{licitaciones,count:licitaciones.length,alta,media,baja,fechaHoy:hoyDisplay}}];

